#include<bits/stdc++.h>
using namespace std;
int n,m,len,c[200010],k,cnt[200010];
long long sum,ans[200010];
bitset<200010> b;
struct query
{
    int l,r,id;
    bool operator<(const query&b)const
    {
        if(l/len!=b.l/len)
        {
            return l<b.l;
        }
        return (((l/len)&1)?r<b.r:r>b.r);
    }
}a[200010];
void add(int x)
{
    if(cnt[c[x]]==0)
    {
        b.set(c[x],0);
    }
    cnt[c[x]]++;
}
void del(int x)
{
    cnt[c[x]]--;
    if(cnt[c[x]]==0)
    {
        b.set(c[x],1);
    }
}
int main()
{
    scanf("%d%d",&n,&m);
    len=sqrt(n);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&c[i]);
    }
    for(int i=1;i<=m;i++)
    {
        scanf("%d%d",&a[i].l,&a[i].r);
        a[i].id=i;
    }
    sort(a+1,a+1+m);
    int l=1,r=0;
    b.set();
    for(int i=1;i<=m;i++)
    {
        while(l>a[i].l)
        {
            add(--l);
        }
        while(l<a[i].l)
        {
            del(l++);
        }
        while(r>a[i].r)
        {
            del(r--);
        }
        while(r<a[i].r)
        {
            add(++r);
        }
        ans[a[i].id]=b._Find_first();
    }
    for(int i=1;i<=m;i++)
    {
        printf("%lld\n",ans[i]);
    }
    return 0;
}
